import React, { useEffect, useState } from 'react';
import axios from 'axios';

function ListaAlunos({ reloadKey, onEditar }) {
  const [alunos, setAlunos] = useState([]);
  const [carregando, setCarregando] = useState(true);

  useEffect(() => {
    setCarregando(true);
    axios.get('/api/alunos')
      .then((res) => {
        setAlunos(res.data);
        setCarregando(false);
      })
      .catch((err) => {
        console.error('Erro ao buscar alunos:', err);
        setCarregando(false);
      });
  }, [reloadKey]);

  const handleDeletar = (id) => {
    if (window.confirm('Tem certeza que deseja deletar este aluno?')) {
      axios.delete(`/api/alunos/${id}`)
        .then(() => {
          setAlunos(alunos.filter(aluno => aluno.id !== id));
        })
        .catch((err) => alert('Erro ao deletar aluno'));
    }
  };

  if (carregando) return <p>Carregando alunos...</p>;
  if (alunos.length === 0) return <p>Nenhum aluno cadastrado.</p>;

  return (
  <div className="mt-4">
  <h2 className="text-xl font-semibold mb-4 text-[#1d3557]">Lista de Alunos</h2>
  <ul className="space-y-3">
    {alunos.map((aluno) => (
      <li
        key={aluno.id}
        className="flex items-center justify-between bg-gray-50 rounded-xl px-5 py-3 shadow-sm hover:bg-gray-100 transition"
      >
        <div>
          <span className="font-medium text-gray-800">{aluno.nome}</span>
          <span className="ml-4 text-gray-600">RA: {aluno.ra}</span>
          <span className="ml-4 text-gray-500">
            Período: {aluno.periodo_nome} {aluno.turno}
          </span>
        </div>
        <div className="space-x-2">
          <button
            onClick={() => onEditar(aluno)}
            className="px-4 py-1 rounded-lg bg-blue-100 text-blue-800 hover:bg-blue-200 font-semibold transition"
          >
            Editar
          </button>
          <button
            onClick={() => handleDeletar(aluno.id)}
            className="px-4 py-1 rounded-lg bg-red-100 text-red-700 hover:bg-red-200 font-semibold transition"
          >
            Deletar
          </button>
        </div>
      </li>
    ))}
  </ul>
</div>


  );
}

export default ListaAlunos;
